mapper.select:
SELECT u.*, COUNT(d.draft_id) AS post_count FROM users u LEFT JOIN blog_post_drafts d ON u.user_id = d.author_id AND d.is_deleted = false WHERE u.is_deleted = false AND u.role = #{role}
AND (u.first_name LIKE CONCAT('%', #{search}, '%') OR u.last_name LIKE CONCAT('%', #{search}, '%') OR u.display_name LIKE CONCAT('%', #{search}, '%'))
GROUP BY u.user_id ORDER BY u.created_at DESC LIMIT #{limit} OFFSET #{offset}
